PATCHES_B64 = json.loads(r'''{"pipeline_cli.py": "", "AgentLaboratory/inference.py": "", "AgentLaboratory/perm_pipeline/run_perm_pipeline.py": "", "AgentLaboratory/agent_runtime.py": "", "AgentLaboratory/agents.py": "", "AgentLaboratory/ai_lab_repo.py": "", "competitions/cayley-py-megaminx/cayley_adapter.py": "", "competitions/cayley-py-megaminx/search_improver_v3.py": "", "competitions/cayley-py-megaminx/megaminx_cayleypy_llm_hybrid_solver.py": "", "colab/megaminx_full_colab_runner_lowmem.py": ""}''')


def eprint(*args, **kwargs):
    print(*args, file=sys.stderr, **kwargs)


def run(cmd, *, cwd=None, env=None, check=True, capture_output=False, text=True):
    printable = shlex.join([str(x) for x in cmd])
    print(f"$ {printable}")
    return subprocess.run(
        [str(x) for x in cmd],
        cwd=str(cwd) if cwd is not None else None,
        env=env,
        check=check,
        capture_output=capture_output,
        text=text,
    )


def str2bool(v):
    if isinstance(v, bool):
        return v
    s = str(v).strip().lower()
    if s in {"1", "true", "yes", "y", "on"}:
        return True
    if s in {"0", "false", "no", "n", "off"}:
        return False
    raise argparse.ArgumentTypeError(f"Invalid boolean value: {v}")


def split_csv_models(value):
    if value is None:
        return []
    if isinstance(value, (list, tuple)):
        out = []
        for item in value:
            out.extend(split_csv_models(item))
        return out
    text = str(value).strip()
    if not text:
        return []
    return [x.strip() for x in text.split(",") if x.strip()]


def dedupe_keep_order(items):
    seen = set()
    out = []
    for item in items:
        if item and item not in seen:
            seen.add(item)
            out.append(item)
    return out


def parse_agent_models(text: str) -> Dict[str, List[str]]:
    mapping: Dict[str, List[str]] = {}
    raw = str(text or "").strip()
    if not raw:
        return mapping
    for chunk in raw.split(";"):
        chunk = chunk.strip()
        if not chunk or "=" not in chunk:
            continue
        role, models = chunk.split("=", 1)
        role = role.strip()
        model_list = dedupe_keep_order(split_csv_models(models))
        if role and model_list:
            mapping[role] = model_list
    return mapping


def format_agent_models(mapping: Dict[str, List[str]]) -> str:
    parts = []
    for role in ("planner", "coder", "fixer"):
        model_list = dedupe_keep_order(mapping.get(role, []))
        if model_list:
            parts.append(f"{role}=" + ",".join(model_list))
    for role in sorted(mapping.keys()):
        if role in {"planner", "coder", "fixer"}:
            continue
        model_list = dedupe_keep_order(mapping.get(role, []))
        if model_list:
            parts.append(f"{role}=" + ",".join(model_list))
    return ";".join(parts)


def pick_models(models, n):
    if not models:
        return []
    n = max(1, min(int(n), len(models)))
    return list(models[:n])


def maybe_resolve(path_str: Optional[str], base: Path) -> Optional[Path]:
    if not path_str:
        return None
    p = Path(path_str)
    if not p.is_absolute():
        p = base / p
    return p


def clone_or_update_repo(args) -> Path:
    target_dir = Path(args.target_dir).resolve()
    if target_dir.exists():
        print(f"Repository already exists: {target_dir}")
        if (target_dir / ".git").exists():
            try:
                run(["git", "-C", target_dir, "fetch", "origin"], check=True)
                run(["git", "-C", target_dir, "checkout", args.repo_branch], check=True)
                run(["git", "-C", target_dir, "pull", "--ff-only", "origin", args.repo_branch], check=True)
                print("Repository updated from GitHub")
            except Exception as e:
                print("Best-effort update skipped:", e)
        else:
            print("Target dir exists but is not a git repo; using it as-is.")
    else:
        target_dir.parent.mkdir(parents=True, exist_ok=True)
        run(
            ["git", "clone", "--depth", "1", "--branch", args.repo_branch, args.repo_url, target_dir],
            check=True,
        )
    try:
        run(["git", "-C", target_dir, "rev-parse", "HEAD"], check=False)
    except Exception:
        pass
    return target_dir


def install_deps(target_dir: Path, args):
    if args.skip_install_deps:
        print("Skipping dependency installation.")
        return
    py = sys.executable
    run([py, "-m", "pip", "install", "-q", "--upgrade", "pip"], check=True)
    run([py, "-m", "pip", "install", "-q", "kaggle", "psutil", "orjson", "tqdm", "nest_asyncio"], check=True)
    req = target_dir / "gpt4free" / "requirements-min.txt"
    if req.exists():
        run([py, "-m", "pip", "install", "-q", "-r", req], check=True)
    else:
        print(f"Warning: {req} not found; skipping g4f requirements-min install.")
    try:
        run([py, "-m", "pip", "install", "-q", "git+https://github.com/cayleypy/cayleypy"], check=True)
    except Exception as e:
        print("GitHub CayleyPy install failed; trying PyPI fallback:", e)
        run([py, "-m", "pip", "install", "-q", "cayleypy"], check=True)


def set_env_kv_pairs(env_pairs):
    for pair in env_pairs:
        if "=" not in pair:
            raise ValueError(f"Expected KEY=VALUE, got: {pair}")
        key, value = pair.split("=", 1)
        os.environ[key] = value
        print(f"Set env {key}")


def configure_g4f_env(args):
    if args.env:
        set_env_kv_pairs(args.env)
    direct_map = {
        "openai_api_key": "OPENAI_API_KEY",
        "gemini_api_key": "GEMINI_API_KEY",
        "anthropic_api_key": "ANTHROPIC_API_KEY",
        "groq_api_key": "GROQ_API_KEY",
        "openrouter_api_key": "OPENROUTER_API_KEY",
        "huggingface_api_key": "HUGGINGFACE_API_KEY",
        "deepinfra_api_key": "DEEPINFRA_API_KEY",
        "together_api_key": "TOGETHER_API_KEY",
    }
    for arg_name, env_name in direct_map.items():
        value = getattr(args, arg_name, "")
        if value:
            os.environ[env_name] = value
            print(f"Set env {env_name}")


def classify_kaggle_payload(raw_bytes: bytes):
    raw = raw_bytes.decode("utf-8", errors="ignore").strip()
    payload = None
    try:
        payload = json.loads(raw)
    except Exception:
        payload = None

    if isinstance(payload, dict) and payload.get("username") and payload.get("key"):
        return "kaggle.json", raw_bytes
    if isinstance(payload, dict) and any(payload.get(k) for k in ("api_token", "access_token", "token")):
        token = payload.get("api_token") or payload.get("access_token") or payload.get("token")
        return "access_token", str(token).encode("utf-8")
    if raw and "\n" not in raw and not raw.startswith("{"):
        return "access_token", raw.encode("utf-8")
    return None, None


def configure_kaggle_credentials(args):
    if not args.kaggle_credentials:
        print("No --kaggle-credentials provided; using existing ~/.kaggle if present.")
        return
    src = Path(args.kaggle_credentials).expanduser().resolve()
    if not src.exists():
        raise FileNotFoundError(src)
    kind, payload = classify_kaggle_payload(src.read_bytes())
    if not kind:
        raise RuntimeError(f"Could not classify Kaggle credential file: {src}")
    kaggle_dir = Path.home() / ".kaggle"
    kaggle_dir.mkdir(parents=True, exist_ok=True)
    dst = kaggle_dir / kind
    dst.write_bytes(payload)
    os.chmod(dst, 0o600)
    print(f"Saved {kind} to {dst}")


def apply_patches(target_dir: Path):
    for rel_path, payload in PATCHES_B64.items():
        text = zlib.decompress(base64.b64decode(payload)).decode("utf-8")
        target = target_dir / rel_path
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text(text, encoding="utf-8")
        print("patched", rel_path)
    print("All patches written.")


