def set_runtime_env(args):
    os.environ["PYTHONUNBUFFERED"] = "1"
    os.environ["AGENTLAB_TRIES"] = "3"
    os.environ["AGENTLAB_TIMEOUT"] = str(args.g4f_request_timeout)
    os.environ["G4F_TIMEOUT"] = str(args.g4f_request_timeout)
    os.environ["AGENTLAB_G4F_RECOVERY_ROUNDS"] = str(args.g4f_recovery_rounds)
    os.environ["AGENTLAB_G4F_RECOVERY_MAX_ITERS"] = str(args.g4f_recovery_max_iters)
    os.environ["AGENTLAB_G4F_RECOVERY_SLEEP_S"] = str(args.g4f_recovery_sleep)
    os.environ["AGENTLAB_G4F_REQUEST_TIMEOUT_S"] = str(args.g4f_request_timeout)
    os.environ["AGENTLAB_G4F_USE_ASYNC"] = "1" if args.use_g4f_async else "0"
    os.environ["AGENTLAB_G4F_STOP_AT_PYTHON_FENCE"] = "1"
    os.environ["AGENTLAB_MAX_RESPONSE_CHARS"] = str(args.g4f_max_response_chars)
    os.environ["MEGAMINX_MAX_CACHED_TARGET_GRAPHS"] = "1"
    os.environ["MEGAMINX_MAX_CACHED_BFS_ENTRIES"] = "2"
    if args.g4f_provider:
        os.environ["G4F_PROVIDER"] = str(args.g4f_provider)
    print("Environment configured.")


def ensure_competition_data(target_dir: Path, args):
    comp_dir = target_dir / "competitions" / "cayley-py-megaminx"
    data_dir = comp_dir / "data"
    data_dir.mkdir(parents=True, exist_ok=True)
    need_files = [data_dir / "test.csv", data_dir / "sample_submission.csv"]
    missing = [p for p in need_files if not p.exists()]
    if not missing:
        print("Competition data already present.")
        return comp_dir
    print("Missing:", [str(p) for p in missing])
    dl_dir = target_dir / "_kaggle_download"
    dl_dir.mkdir(parents=True, exist_ok=True)
    run(["kaggle", "competitions", "download", args.competition, "-p", dl_dir, "-q"], check=True)
    for zip_path in dl_dir.glob("*.zip"):
        print("Unzipping", zip_path)
        with zipfile.ZipFile(zip_path, "r") as zf:
            zf.extractall(data_dir)
    print("Competition data prepared in", data_dir)
    return comp_dir


def resolve_models(target_dir: Path, args):
    explicit_pool = dedupe_keep_order(split_csv_models(args.g4f_explicit_model_pool))
    explicit_agent_map = parse_agent_models(args.g4f_explicit_agent_models)
    explicit_any = bool(explicit_pool or explicit_agent_map)

    if explicit_any and args.g4f_skip_probe_when_explicit:
        if explicit_agent_map:
            if not explicit_pool:
                merged = []
                for role_models in explicit_agent_map.values():
                    merged.extend(role_models)
                explicit_pool = dedupe_keep_order(merged)
            if explicit_pool:
                for role in ("planner", "coder", "fixer"):
                    explicit_agent_map.setdefault(role, explicit_pool[:1] or [])
        else:
            if not explicit_pool:
                raise RuntimeError("Explicit g4f configuration is enabled, but no models were provided.")
            explicit_agent_map = {
                "planner": pick_models(explicit_pool, 2),
                "coder": pick_models(explicit_pool, 3),
                "fixer": pick_models(list(reversed(explicit_pool)), 2),
            }

        working = explicit_pool[: max(1, int(args.g4f_working_model_limit))] if explicit_pool else []
        if not working:
            merged = []
            for role in ("planner", "coder", "fixer"):
                merged.extend(explicit_agent_map.get(role, []))
            working = dedupe_keep_order(merged)[: max(1, int(args.g4f_working_model_limit))]

        model_pool = ",".join(working)
        agent_models = format_agent_models(explicit_agent_map)
        print("Using explicit g4f models; probe skipped.")
        print("WORKING_G4F_MODELS =", working)
        print("MODEL_POOL =", model_pool)
        print("AGENT_MODELS =", agent_models)
        return working, model_pool, agent_models

    probe_cmd = [
        sys.executable,
        "pipeline_cli.py",
        "check-g4f-models",
        "--json",
        "--probe-mode", args.g4f_probe_mode,
        "--timeout", str(min(30.0, float(args.g4f_request_timeout))),
        "--max-models", str(args.g4f_max_models_to_probe),
    ]
    if args.g4f_provider:
        probe_cmd += ["--provider", str(args.g4f_provider)]
    if args.g4f_backend_api_url:
        probe_cmd += ["--backend-api-url", str(args.g4f_backend_api_url)]

    res = run(probe_cmd, capture_output=True, cwd=target_dir, check=False)
    if res.stdout:
        print(res.stdout)
    if res.returncode != 0:
        if res.stderr:
            eprint(res.stderr)
        raise SystemExit(f"g4f probe failed with code {res.returncode}")

    payload = json.loads(res.stdout)
    working = payload.get("working_models") or []
    if not working:
        raise RuntimeError(
            "No working g4f models found. Try setting --g4f-provider, API keys, "
            "or use --g4f-explicit-model-pool / --g4f-explicit-agent-models."
        )

    working = working[: max(1, int(args.g4f_working_model_limit))]
    model_pool = ",".join(working)
    planner_models = ",".join(pick_models(working, 2))
    coder_models = ",".join(pick_models(working, 3))
    fixer_models = ",".join(pick_models(list(reversed(working)), 2))
    agent_models = f"planner={planner_models};coder={coder_models};fixer={fixer_models}"

    print("WORKING_G4F_MODELS =", working)
    print("MODEL_POOL =", model_pool)
    print("AGENT_MODELS =", agent_models)
    return working, model_pool, agent_models


def _pick_recent_csv(search_roots, start_ts: float) -> Optional[Path]:
    recent_csvs = []
    seen = set()
    for root in search_roots:
        if not root.exists():
            continue
        for csv_path in root.rglob("*.csv"):
            try:
                stat = csv_path.stat()
            except FileNotFoundError:
                continue
            key = str(csv_path.resolve())
            if key in seen:
                continue
            seen.add(key)
            if stat.st_mtime >= start_ts - 2:
                recent_csvs.append(csv_path)
    if not recent_csvs:
        return None
    recent_csvs.sort(key=lambda p: p.stat().st_mtime, reverse=True)
    return recent_csvs[0]


def _validate_submission_csv(csv_path: Path) -> None:
    with csv_path.open(newline="", encoding="utf-8") as f:
        rows = list(csv.DictReader(f))
    if not rows:
        raise RuntimeError(f"Submission CSV is empty: {csv_path}")
    fieldnames = list(rows[0].keys())
    expected = ["initial_state_id", "path"]
    if fieldnames != expected:
        raise RuntimeError(f"Submission CSV has unexpected columns {fieldnames!r}; expected {expected!r}: {csv_path}")


def run_custom_baseline(target_dir: Path, args) -> Optional[Path]:
    submissions_dir = target_dir / "competitions" / "cayley-py-megaminx" / "submissions"
    submissions_dir.mkdir(parents=True, exist_ok=True)
    if not args.baseline_script:
        return None

    custom_script = Path(args.baseline_script).expanduser().resolve()
    if not custom_script.exists():
        raise FileNotFoundError(custom_script)

    candidate_out = maybe_resolve(args.baseline_script_output_csv, target_dir) or (submissions_dir / f"{args.run_name}_uploaded_baseline.csv")
    candidate_out.parent.mkdir(parents=True, exist_ok=True)

    if candidate_out.exists():
        print(f"Removing stale baseline CSV before rerun: {candidate_out}")
        candidate_out.unlink()

    env = os.environ.copy()
    env["MEGAMINX_REPO_ROOT"] = str(target_dir)
    env["MEGAMINX_COMPETITION_DIR"] = str(target_dir / "competitions" / "cayley-py-megaminx")
    env["MEGAMINX_DATA_DIR"] = str(target_dir / "competitions" / "cayley-py-megaminx" / "data")
    env["MEGAMINX_OUTPUT_CSV"] = str(candidate_out)

    extra_args = shlex.split(str(args.baseline_script_args or "").strip())
    attempts = [
        [args.baseline_script_interpreter, str(custom_script), "--out", str(candidate_out), *extra_args],
        [args.baseline_script_interpreter, str(custom_script), "--output", str(candidate_out), *extra_args],
        [args.baseline_script_interpreter, str(custom_script), *extra_args],
    ]

    start_ts = time.time()
    last_return_code = None
    for i, cmd in enumerate(attempts, start=1):
        print(f"Baseline attempt {i}")
        proc = run(cmd, cwd=target_dir, env=env, check=False)
        last_return_code = proc.returncode
        if candidate_out.exists():
            break

    if not candidate_out.exists():
        recent = _pick_recent_csv([submissions_dir, custom_script.parent, target_dir], start_ts)
        if recent is not None:
            candidate_out = recent

    if not candidate_out.exists():
        raise RuntimeError(
            "Baseline script finished without a detectable CSV output. "
            "Either write to $MEGAMINX_OUTPUT_CSV, support --out/--output, "
            f"or use --baseline-script-output-csv. Last return code: {last_return_code}"
        )

    _validate_submission_csv(candidate_out)
    print("Using baseline CSV:", candidate_out)
    return candidate_out


def run_baseline(target_dir: Path, args, model_pool: str, agent_models: str) -> Path:
    submissions_dir = target_dir / "competitions" / "cayley-py-megaminx" / "submissions"
    submissions_dir.mkdir(parents=True, exist_ok=True)

    custom_baseline = run_custom_baseline(target_dir, args)

    hybrid_out = submissions_dir / "submission_megaminx_g4f_hybrid.csv"
    hybrid_solver = target_dir / "competitions" / "cayley-py-megaminx" / "megaminx_cayleypy_llm_hybrid_solver.py"

    cmd = [
        sys.executable,
        str(hybrid_solver),
        "--out", str(hybrid_out),
        "--models", model_pool,
        "--agent-models", agent_models,
    ]
    if custom_baseline is not None:
        cmd += ["--baseline", str(custom_baseline), "--candidate", str(custom_baseline)]
    if args.generate_llm:
        cmd += ["--generate-llm", "--llm-variants", args.llm_variants]
    if args.keep_improving_llm:
        cmd += ["--keep-improving-llm", "--llm-improvement-rounds", str(args.llm_improvement_rounds)]
    if args.search_v3_before_refine:
        cmd += ["--run-search-v3", "--search-v3-top-k", str(args.search_v3_top_k)]
        if custom_baseline is not None:
            cmd += ["--search-v3-source", str(custom_baseline)]
    cmd += ["--skip-post-refine"]
    if args.disable_cayleypy:
        cmd += ["--disable-cayleypy"]

    run(cmd, cwd=target_dir, check=True)
    print("Hybrid candidate:", hybrid_out, "exists=", hybrid_out.exists())
    if hybrid_out.exists():
        _validate_submission_csv(hybrid_out)
        return hybrid_out
    if custom_baseline is not None:
        return custom_baseline
    raise RuntimeError(f"Hybrid candidate was not produced: {hybrid_out}")


def run_refine(target_dir: Path, args, baseline_csv: Path):
    runner = target_dir / "colab" / "megaminx_full_colab_runner_lowmem.py"
    cmd = [
        sys.executable,
        str(runner),
        "--repo-root", str(target_dir),
        "--run-name", args.run_name,
        "--baseline", str(baseline_csv),
        "--chunk-size", str(args.chunk_size),
        "--max-passes", str(args.max_passes),
        "--profile-mode", args.profile_mode,
        "--min-improvement", str(args.min_improvement),
        "--light-min-path-len", str(args.light_min_path_len),
        "--aggressive-min-path-len", str(args.aggressive_min_path_len),
        "--force-aggressive-top-n", str(args.force_aggressive_top_n),
        "--light-time-budget-per-row", str(args.light_time_budget_per_row),
        "--aggressive-time-budget-per-row", str(args.aggressive_time_budget_per_row),
        "--light-beam-width", str(args.light_beam_width),
        "--aggressive-beam-width", str(args.aggressive_beam_width),
        "--light-max-steps", str(args.light_max_steps),
        "--aggressive-max-steps", str(args.aggressive_max_steps),
        "--light-history-depth", str(args.light_history_depth),
        "--aggressive-history-depth", str(args.aggressive_history_depth),
        "--light-mitm-depth", str(args.light_mitm_depth),
        "--aggressive-mitm-depth", str(args.aggressive_mitm_depth),
        "--light-window-lengths", args.light_window_lengths,
        "--aggressive-window-lengths", args.aggressive_window_lengths,
        "--light-window-samples", str(args.light_window_samples),
        "--aggressive-window-samples", str(args.aggressive_window_samples),
        "--light-beam-mode", args.light_beam_mode,
        "--aggressive-beam-mode", args.aggressive_beam_mode,
        "--search-v3-top-k", str(args.search_v3_top_k),
    ]
    if args.disable_cayleypy:
        cmd.append("--disable-cayleypy")

    run(cmd, cwd=target_dir, check=True)
    summary_path = target_dir / "colab_runs" / args.run_name / "run_summary.json"
    summary = json.loads(summary_path.read_text(encoding="utf-8"))
    final_submission = Path(summary["final_submission"])
    print("FINAL_SUBMISSION =", final_submission)
    print(json.dumps(summary, indent=2, ensure_ascii=False)[:5000])
    return final_submission, summary_path


def validate_submission(target_dir: Path, args, final_submission: Path, summary_path: Path):
    comp_dir = target_dir / "competitions" / "cayley-py-megaminx"
    solve_module_path = comp_dir / "solve_module.py"
    test_csv_path = comp_dir / "data" / "test.csv"
    sample_path = comp_dir / "data" / "sample_submission.csv"

    spec = importlib.util.spec_from_file_location("megaminx_validate_solve_module", solve_module_path)
    mod = importlib.util.module_from_spec(spec)
    sys.modules["megaminx_validate_solve_module"] = mod
    assert spec.loader is not None
    spec.loader.exec_module(mod)

    central, generators = mod.load_puzzle_bundle()

    def read_rows(path):
        with path.open(newline="", encoding="utf-8") as f:
            return list(csv.DictReader(f))

    sub_rows = read_rows(final_submission)
    test_rows = read_rows(test_csv_path)
    sample_rows = read_rows(sample_path)

    assert len(sub_rows) == len(test_rows) == len(sample_rows), (len(sub_rows), len(test_rows), len(sample_rows))

    schema_ok = list(sub_rows[0].keys()) == list(sample_rows[0].keys())
    id_ok = [r["initial_state_id"] for r in sub_rows] == [r["initial_state_id"] for r in sample_rows]

    valid_rows = 0
    invalid_examples = []
    score = 0
    for idx, (srow, trow) in enumerate(zip(sub_rows, test_rows)):
        path = str(srow.get("path") or "").strip()
        moves = mod.path_to_moves(path)
        state = [int(x) for x in str(trow.get("initial_state") or "").split(",") if x != ""]
        final_state = mod.apply_moves(state, moves, generators)
        if list(final_state) == list(central):
            valid_rows += 1
        elif len(invalid_examples) < 20:
            invalid_examples.append({"row_index": idx, "path_preview": path[:200]})
        score += len(moves)
        if idx % 100 == 0:
            gc.collect()

    validation = {
        "rows": len(sub_rows),
        "schema_ok": schema_ok,
        "ids_ok": id_ok,
        "valid_rows": valid_rows,
        "invalid_rows": len(sub_rows) - valid_rows,
        "invalid_examples": invalid_examples,
        "score": score,
        "final_submission": str(final_submission),
    }
    run_dir = target_dir / "colab_runs" / args.run_name
    val_path = run_dir / "final_validation.json"
    val_path.write_text(json.dumps(validation, indent=2, ensure_ascii=False), encoding="utf-8")
    print(json.dumps(validation, indent=2, ensure_ascii=False))

    bundle_path = run_dir / "megaminx_run_artifacts.zip"
    with zipfile.ZipFile(bundle_path, "w", zipfile.ZIP_DEFLATED) as zf:
        zf.write(final_submission, arcname="submission_final.csv")
        zf.write(val_path, arcname="final_validation.json")
        if summary_path.exists():
            zf.write(summary_path, arcname="run_summary.json")
    print("Artifact bundle:", bundle_path)
    return validation, val_path, bundle_path


def submit_to_kaggle(target_dir: Path, args, final_submission: Path):
    if not args.submit_to_kaggle:
        print("submit_to_kaggle = False, submit skipped.")
        return
    if not final_submission.exists():
        raise FileNotFoundError(final_submission)
    run([
        "kaggle", "competitions", "submit", args.competition,
        "-f", str(final_submission),
        "-m", args.submission_message,
    ], cwd=target_dir, check=True)
    print("\nRecent submissions:")
    run(["kaggle", "competitions", "submissions", args.competition], cwd=target_dir, check=False)


