    p = argparse.ArgumentParser(description="Megaminx full run to Kaggle with g4f models.")
    p.add_argument("--repo-url", default="https://github.com/visualcomments/agents_4_puzzles")
    p.add_argument("--repo-branch", default="main")
    p.add_argument("--target-dir", default=str(Path.cwd() / "agents_4_puzzles-main"))
    p.add_argument("--competition", default="cayley-py-megaminx")
    p.add_argument("--skip-install-deps", action="store_true")
    p.add_argument("--skip-syntax-check", action="store_true")
    p.add_argument("--kaggle-credentials", default="", help="Path to kaggle.json, access_token, or JSON token file.")
    p.add_argument("--env", action="append", default=[], help="Extra env in KEY=VALUE format; can be repeated.")

    p.add_argument("--openai-api-key", default="")
    p.add_argument("--gemini-api-key", default="")
    p.add_argument("--anthropic-api-key", default="")
    p.add_argument("--groq-api-key", default="")
    p.add_argument("--openrouter-api-key", default="")
    p.add_argument("--huggingface-api-key", default="")
    p.add_argument("--deepinfra-api-key", default="")
    p.add_argument("--together-api-key", default="")

    p.add_argument("--g4f-provider", default=None)
    p.add_argument("--g4f-backend-api-url", default=None)
    p.add_argument("--g4f-probe-mode", default="pipeline", choices=["pipeline", "async"])
    p.add_argument("--g4f-max-models-to-probe", type=int, default=10)
    p.add_argument("--g4f-working-model-limit", type=int, default=4)
    p.add_argument("--use-g4f-async", type=str2bool, default=True)
    p.add_argument("--g4f-request-timeout", type=float, default=90.0)
    p.add_argument("--g4f-recovery-rounds", type=int, default=2)
    p.add_argument("--g4f-recovery-max-iters", type=int, default=2)
    p.add_argument("--g4f-recovery-sleep", type=float, default=1.5)
    p.add_argument("--g4f-max-response-chars", type=int, default=32000)
    p.add_argument("--g4f-explicit-model-pool", default="")
    p.add_argument("--g4f-explicit-agent-models", default="")
    p.add_argument("--g4f-skip-probe-when-explicit", type=str2bool, default=True)

    p.add_argument("--generate-llm", type=str2bool, default=True)
    p.add_argument("--llm-variants", default="structured,heuristic_boosted,master_hybrid")
    p.add_argument("--keep-improving-llm", type=str2bool, default=True)
    p.add_argument("--llm-improvement-rounds", type=int, default=4)
    p.add_argument("--search-v3-before-refine", type=str2bool, default=True)
